package contracts

import (
	"encoding/hex"
	"math/big"
	"testing"

	"github.com/ethereum/go-ethereum/common"
	"github.com/ethereum/go-ethereum/core/rawdb"
	"github.com/ethereum/go-ethereum/core/state"
	"github.com/ethereum/go-ethereum/core/tracing"
	"github.com/ethereum/go-ethereum/core/types"
	"github.com/ethereum/go-ethereum/crypto"
	"github.com/ethereum/go-ethereum/params"
	"github.com/ethereum/go-ethereum/triedb"
)

// cUSD implementation bytecode deployed by Mento on Celo mainnet at
// 0x4b9b0e94197b7b2b11d311239e1420106ce7a2a2 (implementation behind the
// cUSD proxy at 0x765DE816845861e75A25fCA122bb6898B8B1282a).
// Compiled with Solidity 0.8.24, which emits the PUSH0 opcode (EIP-3855).
var mentoStableTokenV2Hex = ""

// TestCeloBackendCallContractWithPush0 verifies that CeloBackend.CallContract
// can execute contracts containing the PUSH0 opcode (EIP-3855, Shanghai).
//
// This is a regression test for a bug where CeloBackend created the EVM with
// Time: 0, causing the EVM to use pre-Shanghai instruction sets that don't
// include PUSH0. Contracts compiled with Solidity >= 0.8.20 emit PUSH0 by
// default, so balance lookups for fee currencies using such contracts would
// fail with an invalid opcode error, causing GetFeeBalance to return nil.
//
// The test uses the actual Mento StableTokenV2 (cUSD) implementation bytecode
// deployed on Celo mainnet, which is compiled with Solidity 0.8.24 and uses
// PUSH0 extensively.
//
// See also https://github.com/celo-org/celo-blockchain-planning/issues/1357
func TestCeloBackendCallContractWithPush0(t *testing.T) {
	shanghaiTime := uint64(100)

	// Chain config where Shanghai activates at timestamp 100.
	// This simulates mainnet where Shanghai activated at a specific time,
	// as opposed to dev mode where it activates at time 0.
	config := &params.ChainConfig{
		ChainID:                 big.NewInt(42220),
		HomesteadBlock:          big.NewInt(0),
		EIP150Block:             big.NewInt(0),
		EIP155Block:             big.NewInt(0),
		EIP158Block:             big.NewInt(0),
		ByzantiumBlock:          big.NewInt(0),
		ConstantinopleBlock:     big.NewInt(0),
		PetersburgBlock:         big.NewInt(0),
		IstanbulBlock:           big.NewInt(0),
		BerlinBlock:             big.NewInt(0),
		LondonBlock:             big.NewInt(0),
		MergeNetsplitBlock:      big.NewInt(0),
		ShanghaiTime:            &shanghaiTime,
		TerminalTotalDifficulty: big.NewInt(0),
	}

	mentoImpl, err := hex.DecodeString(mentoStableTokenV2Hex)
	if err != nil {
		t.Fatal(err)
	}

	contractAddr := common.HexToAddress("0x765DE816845861e75A25fCA122bb6898B8B1282a")
	accountAddr := common.HexToAddress("0xBFce5EF4F16522D9059dA2776e4619F893A955cf")
	expectedBalance := big.NewInt(10000000000000000) // 1e16, matches mainnet

	// _balances mapping is at storage slot 5 in the StableTokenV2 contract.
	// Storage key = keccak256(abi.encode(account, uint256(5)))
	balanceSlot := crypto.Keccak256Hash(
		common.LeftPadBytes(accountAddr.Bytes(), 32),
		common.LeftPadBytes(big.NewInt(5).Bytes(), 32),
	)

	newState := func() *state.StateDB {
		memDb := rawdb.NewMemoryDatabase()
		tdb := triedb.NewDatabase(memDb, triedb.HashDefaults)
		statedb, err := state.New(types.EmptyRootHash, state.NewDatabase(tdb, nil))
		if err != nil {
			t.Fatal(err)
		}
		statedb.SetCode(contractAddr, mentoImpl, tracing.CodeChangeUnspecified)
		statedb.SetState(contractAddr, balanceSlot, common.BigToHash(expectedBalance))
		return statedb
	}

	// CeloBackend with Time set to post-Shanghai. Before the fix,
	// CeloBackend hardcoded Time to 0 (pre-Shanghai), so PUSH0 would
	// fail. After the fix, it uses the provided Time field.
	backend := &CeloBackend{
		ChainConfig: config,
		State:       newState(),
		BlockNumber: big.NewInt(1),
		Time:        shanghaiTime,
	}

	feeCurrency := contractAddr
	result := GetFeeBalance(backend, accountAddr, &feeCurrency)
	if result == nil {
		t.Fatal("GetFeeBalance returned nil")
	}
	if result.Cmp(expectedBalance) != 0 {
		t.Fatalf("expected fee balance %v, got %v", expectedBalance, result)
	}
}
